"use client"

import {
  OrdinalsGridUI,
  type OrdinalsGridUIProps,
} from "./ordinals-grid-ui"
import {
  useOrdinalsGrid,
  type OrdinalOutput,
  type UseOrdinalsGridOptions,
  type UseOrdinalsGridReturn,
} from "./use-ordinals-grid"

// ---------------------------------------------------------------------------
// Re-exports
// ---------------------------------------------------------------------------

export {
  OrdinalsGridUI,
  type OrdinalsGridUIProps,
} from "./ordinals-grid-ui"
export {
  useOrdinalsGrid,
  type OrdinalOutput,
  type UseOrdinalsGridOptions,
  type UseOrdinalsGridReturn,
} from "./use-ordinals-grid"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface OrdinalsGridProps {
  /** Ordinal address to fetch from the 1sat API */
  address?: string
  /** Pre-fetched ordinals to display (bypasses API fetch) */
  ordinals?: OrdinalOutput[]
  /** Base URL for the 1sat owner API */
  apiUrl?: string
  /** Max number of items to display */
  limit?: number
  /** Called when an ordinal card is clicked */
  onSelect?: (ordinal: OrdinalOutput) => void
  /** Whether to show the item count header (default: true) */
  showCount?: boolean
  /** Whether to wrap the grid in a ScrollArea (default: false) */
  scrollable?: boolean
  /** Max height for the scroll area when scrollable is true */
  maxHeight?: string
  /** Additional CSS classes */
  className?: string
}

// ---------------------------------------------------------------------------
// Composed component
// ---------------------------------------------------------------------------

/**
 * Responsive grid of owned ordinal NFTs with ORDFS thumbnails.
 *
 * Supply either an `address` to auto-fetch from the 1sat API, or pass
 * pre-fetched `ordinals` directly. Each card displays the inscription
 * image, name, content type badge, and truncated outpoint.
 *
 * @example
 * ```tsx
 * import { OrdinalsGrid } from "@/components/blocks/ordinals-grid"
 *
 * // Fetch from address
 * <OrdinalsGrid
 *   address="1A1zP1eP5QGefi2DMPTfTL5SLmv7DivfNa"
 *   onSelect={(ordinal) => console.log("Selected:", ordinal.outpoint)}
 * />
 *
 * // Or pass pre-fetched ordinals
 * <OrdinalsGrid
 *   ordinals={myOrdinals}
 *   onSelect={(ordinal) => router.push(`/ordinal/${ordinal.outpoint}`)}
 * />
 * ```
 */
export function OrdinalsGrid({
  address,
  ordinals,
  apiUrl,
  limit,
  onSelect,
  showCount,
  scrollable,
  maxHeight,
  className,
}: OrdinalsGridProps) {
  const grid = useOrdinalsGrid({ address, ordinals, apiUrl, limit })

  return (
    <OrdinalsGridUI
      items={grid.items}
      isLoading={grid.isLoading}
      error={grid.error}
      count={grid.count}
      onSelect={onSelect}
      showCount={showCount}
      scrollable={scrollable}
      maxHeight={maxHeight}
      className={className}
    />
  )
}

"use client"

import { useCallback, useState } from "react"
import { cn } from "@/lib/utils"
import { Card, CardContent } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Skeleton } from "@/components/ui/skeleton"
import { ScrollArea } from "@/components/ui/scroll-area"
import { ImageOff, Grid2x2 } from "lucide-react"
import type { OrdinalOutput } from "./use-ordinals-grid"

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const ORDFS_BASE = "https://ordfs.network"

/** Number of skeleton cards to show during loading */
const SKELETON_COUNT = 8

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface OrdinalsGridUIProps {
  /** Ordinal items to display */
  items: OrdinalOutput[]
  /** Whether the grid is in a loading state */
  isLoading: boolean
  /** Error to display */
  error: Error | null
  /** Total count of items */
  count: number
  /** Called when an ordinal card is clicked */
  onSelect?: (ordinal: OrdinalOutput) => void
  /** Whether to show the item count header (default: true) */
  showCount?: boolean
  /** Whether to wrap the grid in a ScrollArea (default: false) */
  scrollable?: boolean
  /** Max height for the scroll area when scrollable is true */
  maxHeight?: string
  /** Additional CSS classes for the root container */
  className?: string
}

// ---------------------------------------------------------------------------
// Sub-components
// ---------------------------------------------------------------------------

interface OrdinalThumbnailProps {
  origin: string
  name: string | undefined
  outpoint: string
}

function OrdinalThumbnail({ origin, name, outpoint }: OrdinalThumbnailProps) {
  const [hasError, setHasError] = useState(false)
  const [isImageLoading, setIsImageLoading] = useState(true)

  const handleError = useCallback(() => {
    setHasError(true)
    setIsImageLoading(false)
  }, [])

  const handleLoad = useCallback(() => {
    setIsImageLoading(false)
  }, [])

  const alt = name ?? `Ordinal ${outpoint.slice(0, 8)}...`
  const src = `${ORDFS_BASE}/content/${origin}`

  if (hasError) {
    return (
      <div className="flex h-full w-full items-center justify-center bg-muted">
        <ImageOff
          className="size-8 text-muted-foreground/50"
          aria-hidden="true"
        />
      </div>
    )
  }

  return (
    <>
      {isImageLoading && (
        <Skeleton className="absolute inset-0 h-full w-full rounded-none" />
      )}
      <img
        src={src}
        alt={alt}
        className={cn(
          "h-full w-full object-cover transition-transform duration-200 group-hover:scale-105",
          isImageLoading && "invisible",
        )}
        loading="lazy"
        onError={handleError}
        onLoad={handleLoad}
      />
    </>
  )
}

interface OrdinalCardProps {
  ordinal: OrdinalOutput
  onSelect?: (ordinal: OrdinalOutput) => void
}

function OrdinalCard({ ordinal, onSelect }: OrdinalCardProps) {
  const truncatedOutpoint =
    ordinal.outpoint.length > 16
      ? `${ordinal.outpoint.slice(0, 8)}...${ordinal.outpoint.slice(-6)}`
      : ordinal.outpoint

  const handleClick = useCallback(() => {
    onSelect?.(ordinal)
  }, [ordinal, onSelect])

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === "Enter" || e.key === " ") {
        e.preventDefault()
        onSelect?.(ordinal)
      }
    },
    [ordinal, onSelect],
  )

  return (
    <Card
      className={cn(
        "group overflow-hidden transition-all duration-200",
        "hover:shadow-md hover:border-primary/30",
        onSelect && "cursor-pointer",
      )}
      role={onSelect ? "button" : undefined}
      tabIndex={onSelect ? 0 : undefined}
      aria-label={
        ordinal.name
          ? `Ordinal: ${ordinal.name}`
          : `Ordinal ${truncatedOutpoint}`
      }
      onClick={onSelect ? handleClick : undefined}
      onKeyDown={onSelect ? handleKeyDown : undefined}
    >
      <div className="relative aspect-square overflow-hidden bg-muted/50">
        <OrdinalThumbnail
          origin={ordinal.origin}
          name={ordinal.name}
          outpoint={ordinal.outpoint}
        />
      </div>
      <CardContent className="flex flex-col gap-1.5 p-3">
        {ordinal.name ? (
          <p className="truncate text-sm font-medium leading-none">
            {ordinal.name}
          </p>
        ) : (
          <p className="truncate text-sm font-medium leading-none text-muted-foreground">
            Unnamed
          </p>
        )}
        <div className="flex items-center justify-between gap-2">
          {ordinal.contentType && (
            <Badge variant="secondary" className="text-[10px] px-1.5 py-0">
              {ordinal.contentType.split("/").pop()}
            </Badge>
          )}
          <span className="truncate text-[11px] font-mono text-muted-foreground">
            {truncatedOutpoint}
          </span>
        </div>
      </CardContent>
    </Card>
  )
}

// ---------------------------------------------------------------------------
// Loading skeleton
// ---------------------------------------------------------------------------

function SkeletonGrid() {
  return (
    <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 md:grid-cols-4">
      {Array.from({ length: SKELETON_COUNT }, (_, i) => (
        <Card key={i} className="overflow-hidden">
          <Skeleton className="aspect-square w-full rounded-none" />
          <div className="flex flex-col gap-2 p-3">
            <Skeleton className="h-4 w-3/4" />
            <div className="flex items-center justify-between gap-2">
              <Skeleton className="h-4 w-12" />
              <Skeleton className="h-3 w-20" />
            </div>
          </div>
        </Card>
      ))}
    </div>
  )
}

// ---------------------------------------------------------------------------
// Empty state
// ---------------------------------------------------------------------------

function EmptyState() {
  return (
    <div className="flex flex-col items-center justify-center py-16 text-center">
      <div className="mb-3 flex size-12 items-center justify-center rounded-full bg-muted">
        <Grid2x2
          className="size-6 text-muted-foreground"
          aria-hidden="true"
        />
      </div>
      <p className="text-sm font-medium text-muted-foreground">
        No ordinals found
      </p>
      <p className="mt-1 text-xs text-muted-foreground/70">
        Ordinals owned by this address will appear here
      </p>
    </div>
  )
}

// ---------------------------------------------------------------------------
// Error state
// ---------------------------------------------------------------------------

interface ErrorStateProps {
  error: Error
}

function ErrorState({ error }: ErrorStateProps) {
  return (
    <div className="flex flex-col items-center justify-center py-16 text-center">
      <p className="text-sm font-medium text-destructive">
        Failed to load ordinals
      </p>
      <p className="mt-1 max-w-sm text-xs text-muted-foreground">
        {error.message}
      </p>
    </div>
  )
}

// ---------------------------------------------------------------------------
// Main UI component
// ---------------------------------------------------------------------------

export function OrdinalsGridUI({
  items,
  isLoading,
  error,
  count,
  onSelect,
  showCount = true,
  scrollable = false,
  maxHeight = "600px",
  className,
}: OrdinalsGridUIProps) {
  // Loading state
  if (isLoading) {
    return (
      <div className={cn("flex flex-col gap-4", className)}>
        {showCount && <Skeleton className="h-5 w-24" />}
        <SkeletonGrid />
      </div>
    )
  }

  // Error state
  if (error) {
    return (
      <div className={className}>
        <ErrorState error={error} />
      </div>
    )
  }

  // Empty state
  if (items.length === 0) {
    return (
      <div className={className}>
        <EmptyState />
      </div>
    )
  }

  const gridContent = (
    <div className="grid grid-cols-2 gap-3 sm:grid-cols-3 md:grid-cols-4">
      {items.map((ordinal) => (
        <OrdinalCard
          key={ordinal.outpoint}
          ordinal={ordinal}
          onSelect={onSelect}
        />
      ))}
    </div>
  )

  return (
    <div className={cn("flex flex-col gap-4", className)}>
      {showCount && (
        <div className="flex items-center justify-between">
          <h3 className="text-sm font-medium text-muted-foreground">
            {count} Ordinal{count !== 1 ? "s" : ""}
          </h3>
        </div>
      )}
      {scrollable ? (
        <ScrollArea style={{ maxHeight }}>{gridContent}</ScrollArea>
      ) : (
        gridContent
      )}
    </div>
  )
}

import { useCallback, useEffect, useMemo, useRef, useState } from "react"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/** Represents a single ordinal NFT output */
export interface OrdinalOutput {
  /** Outpoint in txid_vout or txid.vout format */
  outpoint: string
  /** Content type from tags (e.g. "image/png") */
  contentType: string
  /** Display name from MAP metadata */
  name?: string
  /** Origin outpoint for ORDFS content resolution */
  origin: string
  /** Satoshis held by this output */
  satoshis: number
  /** Raw tags array from the wallet output */
  tags: string[]
}

export interface UseOrdinalsGridOptions {
  /** Ordinal address to fetch from the 1sat API. If omitted, ordinals must be passed via `ordinals` prop. */
  address?: string
  /** Pre-fetched ordinals to display (bypasses API fetch) */
  ordinals?: OrdinalOutput[]
  /** Base URL for the 1sat owner API (default: "https://api.1sat.app/1sat") */
  apiUrl?: string
  /** Max number of items to display (default: unlimited) */
  limit?: number
}

export interface UseOrdinalsGridReturn {
  /** Parsed ordinal items ready for display */
  items: OrdinalOutput[]
  /** Whether the initial fetch is in progress */
  isLoading: boolean
  /** Error from the fetch, if any */
  error: Error | null
  /** Total count of ordinals loaded */
  count: number
  /** Reload ordinals from the API */
  reload: () => void
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

const DEFAULT_API_URL = "https://api.1sat.app/1sat"

/** Extract a tag value by prefix (e.g. "type:" -> "image/png") */
function getTag(tags: string[], prefix: string): string | undefined {
  const tag = tags.find((t) => t.startsWith(prefix))
  return tag ? tag.slice(prefix.length) : undefined
}

/** Normalize an outpoint to underscore format (txid_vout) */
function normalizeOutpoint(outpoint: string): string {
  return outpoint.replace(".", "_")
}

/**
 * Parse a single SSE line from the 1sat owner API into an OrdinalOutput.
 * Expected JSON shape: { outpoint: string, satoshis: number, tags?: string[] }
 */
function parseTxoLine(json: string): OrdinalOutput | null {
  try {
    const data: {
      outpoint: string
      satoshis: number
      tags?: string[]
    } = JSON.parse(json)

    const tags = data.tags ?? []
    const contentType = getTag(tags, "type:") ?? ""
    const name = getTag(tags, "name:")
    const origin = getTag(tags, "origin:") ?? data.outpoint

    return {
      outpoint: normalizeOutpoint(data.outpoint),
      contentType,
      name,
      origin: normalizeOutpoint(origin),
      satoshis: data.satoshis,
      tags,
    }
  } catch {
    return null
  }
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useOrdinalsGrid({
  address,
  ordinals: externalOrdinals,
  apiUrl = DEFAULT_API_URL,
  limit,
}: UseOrdinalsGridOptions = {}): UseOrdinalsGridReturn {
  const [fetchedOrdinals, setFetchedOrdinals] = useState<OrdinalOutput[]>([])
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState<Error | null>(null)
  const abortRef = useRef<AbortController | null>(null)

  const fetchOrdinals = useCallback(
    (addr: string) => {
      // Cancel any in-flight request
      abortRef.current?.abort()

      const controller = new AbortController()
      abortRef.current = controller

      setIsLoading(true)
      setError(null)

      const url = `${apiUrl}/owner/${addr}/txos`
      const items: OrdinalOutput[] = []

      fetch(url, { signal: controller.signal })
        .then(async (response) => {
          if (!response.ok) {
            throw new Error(`Failed to fetch ordinals: ${response.status}`)
          }

          if (!response.body) {
            throw new Error("Response body is null")
          }

          const reader = response.body.getReader()
          const decoder = new TextDecoder()
          let buffer = ""

          for (;;) {
            const { done, value } = await reader.read()
            if (done) break

            buffer += decoder.decode(value, { stream: true })
            const lines = buffer.split("\n")
            // Keep the last incomplete line in the buffer
            buffer = lines.pop() ?? ""

            for (const line of lines) {
              const trimmed = line.trim()
              if (!trimmed) continue

              const parsed = parseTxoLine(trimmed)
              if (parsed) {
                items.push(parsed)
              }
            }
          }

          // Process any remaining buffer
          if (buffer.trim()) {
            const parsed = parseTxoLine(buffer.trim())
            if (parsed) {
              items.push(parsed)
            }
          }

          if (!controller.signal.aborted) {
            setFetchedOrdinals(items)
            setIsLoading(false)
          }
        })
        .catch((err: unknown) => {
          if (controller.signal.aborted) return
          const fetchError =
            err instanceof Error ? err : new Error("Failed to fetch ordinals")
          setError(fetchError)
          setIsLoading(false)
        })
    },
    [apiUrl],
  )

  const reload = useCallback(() => {
    if (address) {
      fetchOrdinals(address)
    }
  }, [address, fetchOrdinals])

  // Fetch on mount or when address changes
  useEffect(() => {
    if (externalOrdinals) return
    if (!address) return

    fetchOrdinals(address)

    return () => {
      abortRef.current?.abort()
    }
  }, [address, externalOrdinals, fetchOrdinals])

  const items = useMemo(() => {
    const source = externalOrdinals ?? fetchedOrdinals
    if (limit !== undefined && limit > 0) {
      return source.slice(0, limit)
    }
    return source
  }, [externalOrdinals, fetchedOrdinals, limit])

  return {
    items,
    isLoading: externalOrdinals ? false : isLoading,
    error: externalOrdinals ? null : error,
    count: items.length,
    reload,
  }
}
